INSERT INTO aggregate.eu_additives (id, e_number, e_number_display, e_number_sort, display_name_en, display_name_lt, identifying_name_en, identifying_name_lt, synonyms_en, synonyms_lt, ins_number, is_group, member_of_group, policy_item_code, source_url, opinion_en, opinion_lt) VALUES (365307, 'E160b(i)', 'E 160b(i)', 160, 'Annatto bixin', 'Anato biksinas', 'Annatto bixin', 'Anato biksinas', NULL, NULL, NULL, FALSE, NULL, 'POL-FAD-IMPORT-3379', 'https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search', 'A natural orange-red colourant extracted from the seeds of the annatto tree, native to tropical regions of the Americas. Used widely in cheeses, butter, margarine, snacks, and processed foods to give that familiar golden or orange hue.
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365307, '315526', '1.4', 'flavoured fermented milk products including heat-treated products', 'aromatizuoti fermentuoto pieno produktai, įskaitant termiškai apdorotus produktus', 'FAD_RT_ML', '15', 'FAD_RU_MGL', NULL, NULL, '94', 'When E 160b(i) (Annatto bixin) and E 160b(ii) (Annatto norbixin) are added in combination, the higher individual maximum level applies to the sum, but the individual maximum levels shall not be exceeded.', 'Kai E 160b(i) (Anatų biksinas) ir E 160b(ii) (Anatų norbiksinas) dedami kartu, aukštesnis individualus didžiausias lygis taikomas jų sumai, tačiau individualių didžiausių lygių viršyti negalima.', 316896);
