INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (365307, 316896, 'COMMISSION REGULATION (EU) 2020/771 of 11 June 2020 amending Annexes II and III to Regulation (EC) No 1333/2008 of the European Parliament and of the Council and the Annex to Commission Regulation (EU) No 231/2012 as regards the use of Annatto, Bixin, Norbixin (E 160b) (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2020/771 2020 m. birželio 11 d., kuriuo iš dalies keičiami Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II ir III priedai ir Komisijos reglamento (ES) Nr. 231/2012 priedas, kiek tai susiję su anaто, biksino, norbiksino (E 160b) naudojimu (Tekstas svarbus EEE)', '(EU) No 2020/0771', NULL, NULL, NULL, 'L184', '25');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (365307, 2684840, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additives (id, e_number, e_number_display, e_number_sort, display_name_en, display_name_lt, identifying_name_en, identifying_name_lt, synonyms_en, synonyms_lt, ins_number, is_group, member_of_group, policy_item_code, source_url, opinion_en, opinion_lt) VALUES (365671, 'E160b(ii)', 'E 160b(ii)', 160, 'Annatto norbixin', 'Anato norbiksinas', 'Annatto norbixin', 'Anato norbiksinas', NULL, NULL, NULL, FALSE, NULL, 'POL-FAD-IMPORT-3380', 'https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search', 'A natural orange-red dye extracted from the seeds of the annatto plant, native to tropical America. It colours everything from cheese rinds and processed cheese to ice cream, jams, and snack foods. The norbixin form is oil-insoluble, making it ideal for surface coatings and water-based products.
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '315526', '1.4', 'flavoured fermented milk products including heat-treated products', 'aromatizuoti fermentuoto pieno produktai, įskaitant termiškai apdorotus produktus', 'FAD_RT_ML', '4', 'FAD_RU_MGL', NULL, NULL, '94', 'When E 160b(i) (Annatto bixin) and E 160b(ii) (Annatto norbixin) are added in combination, the higher individual maximum level applies to the sum, but the individual maximum levels shall not be exceeded.', 'Kai E 160b(i) (Anatų biksinas) ir E 160b(ii) (Anatų norbiksinas) dedami kartu, aukštesnis individualus didžiausias lygis taikomas jų sumai, tačiau individualių didžiausių lygių viršyti negalima.', 316896);
