INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '315934', '12.5', 'Soups and broths', 'Sriubos ir sultiniai', 'FAD_RT_ML', '10', 'FAD_RU_MGK', NULL, NULL, '94', 'When E 160b(i) (Annatto bixin) and E 160b(ii) (Annatto norbixin) are added in combination, the higher individual maximum level applies to the sum, but the individual maximum levels shall not be exceeded.', 'Kai E 160b(i) (Anatų biksinas) ir E 160b(ii) (Anatų norbiksinas) dedami kartu, aukštesnis individualus didžiausias lygis taikomas jų sumai, tačiau individualių didžiausių lygių viršyti negalima.', 316896);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '315938', '12.6', 'Sauces', 'Padažai', 'FAD_RT_ML', '30', 'FAD_RU_MGK', 'including pickles, relishes, chutney and piccalilli; excluding tomato-based sauces’', 'įskaitant marinuotus agurkus, prieskonius, čatnius ir pikalilius; išskyrus pomidorų padažus', '94', 'When E 160b(i) (Annatto bixin) and E 160b(ii) (Annatto norbixin) are added in combination, the higher individual maximum level applies to the sum, but the individual maximum levels shall not be exceeded.', 'Kai E 160b(i) (Anatų biksinas) ir E 160b(ii) (Anatų norbiksinas) dedami kartu, aukštesnis individualus didžiausias lygis taikomas jų sumai, tačiau individualių didžiausių lygių viršyti negalima.', 316896);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '316082', '14.2.8', 'Other alcoholic beverages including mixtures of alcoholic beverages with non-alcoholic beverages and other alcoholic beverages based on distilled alcohol with alcoholic strength by volume less than 15 %', 'Kiti alkoholiniai gėrimai, įskaitant alkoholinių gėrimų mišinius su nealkoholiniais gėrimais ir kitus distiliuotu alkoholiu pagrindu pagamintus alkoholinius gėrimus, kurių faktinė alkoholio koncentracija tūrio procentais yra mažesnė nei 15 %', 'FAD_RT_ML', '10', 'FAD_RU_MGL', 'only alcoholic beverages with alcoholic strength by volume less than 15 %', 'tik alkoholiniai gėrimai, kurių alkoholio kiekis tūrio procentais yra mažesnis nei 15 %', NULL, NULL, NULL, 316896);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '316090', '15.1', 'Potato- cereal- flour- or starch-based snacks', 'Bulvių, grūdų, miltų arba krakmolo pagrindu pagaminti užkandžiai', 'FAD_RT_ML', '20', 'FAD_RU_MGK', NULL, NULL, '94', 'When E 160b(i) (Annatto bixin) and E 160b(ii) (Annatto norbixin) are added in combination, the higher individual maximum level applies to the sum, but the individual maximum levels shall not be exceeded.', 'Kai E 160b(i) (Anatų biksinas) ir E 160b(ii) (Anatų norbiksinas) dedami kartu, aukštesnis individualus didžiausias lygis taikomas jų sumai, tačiau individualių didžiausių lygių viršyti negalima.', 316896);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '316094', '15.2', 'Processed nuts', 'Perdirbtieji riešutai', 'FAD_RT_ML', '10', 'FAD_RU_MGK', NULL, NULL, '94', 'When E 160b(i) (Annatto bixin) and E 160b(ii) (Annatto norbixin) are added in combination, the higher individual maximum level applies to the sum, but the individual maximum levels shall not be exceeded.', 'Kai E 160b(i) (Anatų biksinas) ir E 160b(ii) (Anatų norbiksinas) dedami kartu, aukštesnis individualus didžiausias lygis taikomas jų sumai, tačiau individualių didžiausių lygių viršyti negalima.', 316896);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '316098', '16', 'Desserts excluding products covered in category 1 3 and 4', 'Desertai, išskyrus produktus, kuriems taikomos kategorijos 1, 3 ir 4', 'FAD_RT_ML', '7.5', 'FAD_RU_MGK', NULL, NULL, '94', 'When E 160b(i) (Annatto bixin) and E 160b(ii) (Annatto norbixin) are added in combination, the higher individual maximum level applies to the sum, but the individual maximum levels shall not be exceeded.', 'Kai E 160b(i) (Anatų biksinas) ir E 160b(ii) (Anatų norbiksinas) dedami kartu, aukštesnis individualus didžiausias lygis taikomas jų sumai, tačiau individualių didžiausių lygių viršyti negalima.', 316896);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (365671, 316896, 'COMMISSION REGULATION (EU) 2020/771 of 11 June 2020 amending Annexes II and III to Regulation (EC) No 1333/2008 of the European Parliament and of the Council and the Annex to Commission Regulation (EU) No 231/2012 as regards the use of Annatto, Bixin, Norbixin (E 160b) (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2020/771 2020 m. birželio 11 d., kuriuo iš dalies keičiami Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II ir III priedai ir Komisijos reglamento (ES) Nr. 231/2012 priedas, kiek tai susiję su anaто, biksino, norbiksino (E 160b) naudojimu (Tekstas svarbus EEE)', '(EU) No 2020/0771', NULL, NULL, NULL, 'L184', '25');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (365671, 1764184, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additives (id, e_number, e_number_display, e_number_sort, display_name_en, display_name_lt, identifying_name_en, identifying_name_lt, synonyms_en, synonyms_lt, ins_number, is_group, member_of_group, policy_item_code, source_url, opinion_en, opinion_lt) VALUES (366104, 'E262(ii)', 'E 262(ii)', 262, 'Sodium diacetate', 'Natrio diacetatas', 'Sodium diacetate', 'Natrio diacetatas', NULL, NULL, NULL, FALSE, NULL, 'POL-FAD-IMPORT-3382', 'https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search', 'A preservative and acidity regulator, made by combining sodium acetate with acetic acid — essentially a salt of vinegar. It inhibits mould and bacterial growth, and gives a mild vinegar-like tang. Found mainly in savoury snacks, crackers, and some baked goods.
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (366104, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
