INSERT INTO aggregate.eu_additives (id, e_number, e_number_display, e_number_sort, display_name_en, display_name_lt, identifying_name_en, identifying_name_lt, synonyms_en, synonyms_lt, ins_number, is_group, member_of_group, policy_item_code, source_url, opinion_en, opinion_lt) VALUES (362202, 'E341(iii)', 'E 341 (iii)', 341, 'Tricalcium phosphate', 'Trikalcio fosfatas', 'Tricalcium phosphate', 'Trikalcio fosfatas', NULL, NULL, NULL, FALSE, NULL, 'POL-FAD-IMPORT-3336', 'https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search', 'A mineral salt used as an acidity regulator, anti-caking agent, and calcium supplement in food. It''s the same calcium compound found naturally in bones and teeth. Commonly found in infant formula, baby foods, and processed cereals, where it serves as a calcium source for developing bodies.
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (362202, '315962', '13.1.1', 'infant formulae as defined by Regulation (EU) No 609/2013', 'pradinės formulės, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_ML', '150', 'FAD_RU_MGK', 'Maximum carry-over of 150 mg/kg expressed as P2O5and within the limit for calcium, phosphorus, and the calcium:phosphorus ratio as set in Delegated Regulation (EU) 2016/127', 'Didžiausias pernešimo kiekis – 150 mg/kg, išreikštas P2O5, neviršijant kalcio, fosforo ir kalcio bei fosforo santykio ribų, nustatytų Deleguotajame reglamente (ES) 2016/127', NULL, NULL, NULL, 316236);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (362202, '315966', '13.1.2', 'follow-on formulae as defined by by Regulation (EU) No 609/2013', 'tolesnio maitinimo formulės, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_ML', '150', 'FAD_RU_MGK', 'Maximum carry-over of 150 mg/kg expressed as P2O5and within the limit for calcium, phosphorus, and the calcium:phosphorus ratio as set in Delegated Regulation (EU) 2016/127', 'Didžiausias pernešimo kiekis – 150 mg/kg, išreikštas P2O5, neviršijant kalcio, fosforo ir kalcio bei fosforo santykio ribų, nustatytų Deleguotajame reglamente (ES) 2016/127', NULL, NULL, NULL, 316236);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (362202, '315970', '13.1.3', 'Processed cereal-based foods and baby foods as defined by Regulation (EU) No 609/2013', 'Perdirbtų grūdų pagrindu pagaminti maisto produktai ir kūdikių maistas, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_ML', '1000', 'FAD_RU_MGK', 'Maximum level of 1 000 mg/ kg expressed as P2O5from all uses in final food mentioned in Part E, point 13.1.3, of Annex II is respected', 'Laikomasi didžiausio 1 000 mg/kg lygio, išreikšto P2O5, gaunamo iš visų naudojimo atvejų galutiniame maisto produkte, nurodytų II priedo E dalyje, 13.1.3 punkte', NULL, NULL, NULL, 316236);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (362202, 316236, 'Commission Regulation (EU) 244/2013 of 19/03/2013 amendng Annex III to Regulation (EU) 1333/2008 of the European Parliament and of the Council as regards the use of Tricalcium phosphate (E341 (iii)) in nutrient preparations intended for use in foods for infants and young children. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 244/2013, 2013 m. kovo 19 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (ES) 1333/2008 III priedas dėl trikalcio fosfato (E341 (iii)) naudojimo maistinėse preparatuose, skirtuose kūdikių ir mažų vaikų maiste. Tekstas svarbus EEE', '(EU) No 0244/2013', NULL, NULL, NULL, 'L 77', '3');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (362202, 2684840, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additives (id, e_number, e_number_display, e_number_sort, display_name_en, display_name_lt, identifying_name_en, identifying_name_lt, synonyms_en, synonyms_lt, ins_number, is_group, member_of_group, policy_item_code, source_url, opinion_en, opinion_lt) VALUES (1754010, 'E345(i)', 'E345(i)', 345, 'Trimagnesium dicitrate', 'Trimagnesio dicitratas', 'Trimagnesium dicitrate', 'Trimagnesio dicitratas', NULL, NULL, NULL, FALSE, NULL, 'POL-FAD-10321', 'https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search', 'A magnesium salt of citric acid, used in food supplements as a source of dietary magnesium. Found almost exclusively in solid supplement tablets and capsules. Magnesium itself is an essential mineral involved in hundreds of bodily processes — muscle function, nerve signalling, energy production. This form is generally well-tolerated and considered safe by EFSA at typical supplement doses.', 'Tai magnio druska, gauta iš citrinos rūgšties — naudojama maisto papilduose kaip magnio šaltinis. Randama beveik išimtinai kietose papildų tabletėse ir kapsulėse. Magnis — gyvybiškai svarbus mineralas, dalyvaujantis raumenų veikloje, nervų perdavime ir energijos gamyboje. Ši forma gerai toleruojama ir EFSA laikoma saugia įprastomis papildų dozėmis.');
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (1754010, '316106', '17.1', 'food supplements supplied in a solid form excluding food supplements for infants and young children’,', 'maisto papildai, tiekiami kietos formos, išskyrus maisto papildus kūdikiams ir mažiems vaikams', 'FAD_RT_ML', '100,000', NULL, NULL, NULL, NULL, NULL, NULL, 1753869);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (1754010, 1753869, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additives (id, e_number, e_number_display, e_number_sort, display_name_en, display_name_lt, identifying_name_en, identifying_name_lt, synonyms_en, synonyms_lt, ins_number, is_group, member_of_group, policy_item_code, source_url, opinion_en, opinion_lt) VALUES (364262, 'E450(ix)', 'E 450 (ix)', 450, 'Magnesium dihydrogen diphosphate', 'Magnio dihidrogeno difosfatas', 'Magnesium dihydrogen diphosphate', 'Magnio dihidrogeno difosfatas', NULL, NULL, NULL, FALSE, NULL, 'POL-FAD-IMPORT-3360', 'https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search', 'A leavening agent and acidity regulator, mainly used in baking to help doughs rise and improve texture. Synthetic in origin, but phosphates occur naturally in many foods. Found in breads, noodles, batters, and flour mixes. Generally considered safe by EFSA at typical food levels. High phosphate intake overall — from all dietary sources — is worth watching for people with kidney problems.', 'Rauginimo medžiaga ir rūgštingumo reguliatorius, naudojamas kepiniuose — padeda tešlai kilti ir gerina tekstūrą. Sintetinės kilmės, tačiau fosfatai natūraliai randami daugelyje maisto produktų. Sutinkamas duonoje, makaronuose, tešlos mišiniuose. EFSA laiko saugiu įprastais kiekiais. Tačiau bendras fosfatų kiekis mityboje — iš visų šaltinių kartu — gali kelti problemų žmonėms, turintiems inkstų sutrikimų.');
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (364262, '315754', '6.5', 'Noodles', 'Makaronai', 'FAD_RT_ML', '2000', 'FAD_RU_MGK', NULL, NULL, '4', 'The maximum level is expressed as P2O5', 'Didžiausias lygis išreiškiamas kaip P2O5', 316256);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (364262, '315758', '6.6', 'Batters', 'Tešlos apvalkalai', 'FAD_RT_ML', '12000', 'FAD_RU_MGK', NULL, NULL, '4', 'The maximum level is expressed as P2O5', 'Didžiausias lygis išreiškiamas kaip P2O5', 316256);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (364262, '315782', '7.2', 'Fine bakery wares', 'Smulkūs kepiniai', 'FAD_RT_ML', '15000', NULL, NULL, NULL, '4', 'The maximum level is expressed as P2O5', 'Didžiausias lygis išreiškiamas kaip P2O5', 316256);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (364262, '315718', '6.2.1', 'flours', 'miltai', 'FAD_RT_ML', '15000', 'FAD_RU_MGK', 'only self-raising flour', 'tik savarankiškai kylantys miltai', '4', 'The maximum level is expressed as P2O5', 'Didžiausias lygis išreiškiamas kaip P2O5', 316256);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (364262, '315770', '7.1', 'Bread and rolls', 'Duona ir bandelės', 'FAD_RT_ML', '15000', 'FAD_RU_MGK', 'only pizza dough (frozen or chilled) and tortilla', 'tik picų tešla (šaldyta arba atšaldyta) ir tortilija', '4', 'The maximum level is expressed as P2O5', 'Didžiausias lygis išreiškiamas kaip P2O5', 316256);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (364262, 316256, 'Commission Regulation (EU) 298/2014 of 21/03/2014 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council and the Annex to Commission Regulation (EU) 231/2012 as regards magnesium dihydrogen diphosphate for use as raising agent and acididity regulator. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 298/2014, 2014 m. kovo 21 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas ir Komisijos reglamento (ES) 231/2012 priedas dėl magnio dihidrogeno difosfato naudojimo kaip kildiklio ir rūgštingumo reguliatoriaus. Tekstas svarbus EEE', '(EU) No 0298/2014', NULL, NULL, NULL, 'L 89', '36');
INSERT INTO aggregate.eu_additives (id, e_number, e_number_display, e_number_sort, display_name_en, display_name_lt, identifying_name_en, identifying_name_lt, synonyms_en, synonyms_lt, ins_number, is_group, member_of_group, policy_item_code, source_url, opinion_en, opinion_lt) VALUES (364597, 'E460(ii)', 'E 460(ii)', 460, 'Powdered cellulose', 'Miltelinė celiuliozė', 'Powdered cellulose', 'Miltelinė celiuliozė', NULL, NULL, NULL, FALSE, 'POL-FAD-IMPORT-2981', 'POL-FAD-IMPORT-3365', 'https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search', 'A plant-derived fibre extracted from wood pulp or cotton, used mainly as an anti-caking agent, thickener, and bulking agent. It keeps powdered and grated products from clumping together and adds bulk without adding calories.
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (364597, '315894', '11.4.3', 'table-top sweeteners in tablets', 'stalo saldikliai tabletėmis', 'FAD_RT_QS', NULL, NULL, '', NULL, NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (364597, '315566', '1.7.4', 'whey cheese', 'išrūgų sūris', 'FAD_RT_QS', NULL, NULL, 'only grated and sliced cheese', 'tik tarkuoti ir pjaustytais griežinėliais supjaustyti sūriai', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (364597, '315554', '1.7.1', 'unripened cheese excluding products falling in category 16', 'nesubrandintas sūris, išskyrus produktus, priskiriamus 16 kategorijai', 'FAD_RT_QS', NULL, NULL, 'only grated and sliced mozzarella', 'tik tarkuota ir pjaustytais griežinėliais supjaustyta mozzarella', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (364597, '315574', '1.7.6', 'cheese products (excluding products falling in category 16)', 'sūrio produktai (išskyrus produktus, priklausančius 16 kategorijai)', 'FAD_RT_QS', NULL, NULL, 'only grated and sliced ripened and unripened products; unripened soft spreadable cheese products’', 'tik tarkuoti ir pjaustytais griežinėliais supjaustyti subrandinti ir nesubrandinti produktai; nesubrandinti minkšti tepieji sūrio produktai', NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (364597, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
