INSERT INTO aggregate.eu_additives (id, e_number, e_number_display, e_number_sort, display_name_en, display_name_lt, identifying_name_en, identifying_name_lt, synonyms_en, synonyms_lt, ins_number, is_group, member_of_group, policy_item_code, source_url, opinion_en, opinion_lt) VALUES (1487061, 'E460(i)', 'E 460(i)', 460, 'Microcrystalline cellulose, Cellulose gel', 'Mikrokristalinis celiuliozė, celiuliozės gelis', 'Microcrystalline cellulose, Cellulose gel', 'Mikrokristalinis celiuliozė, celiuliozės gelis', NULL, NULL, NULL, FALSE, 'POL-FAD-IMPORT-2981', 'POL-FAD-IMPORT-3165', 'https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search', 'A plant-derived fibre used as a bulking agent, anti-caking agent, and texturizer. It helps powders flow freely, gives low-fat dairy products a creamier texture, and stabilizes tablets and liquid sweeteners. Derived from purified wood pulp or cotton cellulose — technically natural in origin.
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (1487061, '315542', '1.6.2', 'Unflavoured live fermented cream products and substitute products, both with a fat content of less than 20 %', 'Nearomatizuoti gyvi fermentuoti grietinėlės produktai ir jų pakaitalai, kurių riebalų kiekis mažesnis nei 20 %', 'FAD_RT_QS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 316526);
