INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (1487061, '315554', '1.7.1', 'unripened cheese excluding products falling in category 16', 'nesubrandintas sūris, išskyrus produktus, priskiriamus 16 kategorijai', 'FAD_RT_QS', NULL, NULL, 'only grated and sliced mozzarella', 'tik tarkuota ir pjaustytais griežinėliais supjaustyta mozzarella', NULL, NULL, NULL, 316526);
