INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (1487061, '315558', '1.7.2', 'ripened cheese', 'subrandintas sūris', 'FAD_RT_QS', NULL, NULL, 'only sliced and grated ripened cheese', 'tik supjaustyti griežinėliais ir sutarkuoti prinokę sūriai', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (1487061, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (1487061, 316586, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additives (id, e_number, e_number_display, e_number_sort, display_name_en, display_name_lt, identifying_name_en, identifying_name_lt, synonyms_en, synonyms_lt, ins_number, is_group, member_of_group, policy_item_code, source_url, opinion_en, opinion_lt) VALUES (364381, 'E500(ii)', 'E 500 (ii)', 500, 'Sodium hydrogenate carbonate', 'Natrio hidrokarbonatas', 'Sodium hydrogenate carbonate', 'Natrio hidrokarbonatas', NULL, NULL, NULL, FALSE, NULL, 'POL-FAD-IMPORT-3361', 'https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search', 'A leavening agent and acidity regulator — the same baking soda found in home kitchens. It releases carbon dioxide when heated, helping baked goods rise. Used in limited food categories, including certain dairy products, to adjust acidity or texture. One of the most well-studied and safe food additives in use.', 'Tai kepimo soda — tas pats ingredientas, kurį naudojame namuose kepdami. Veikia kaip rauginimo medžiaga ir rūgštingumo reguliatorius: kaitinamas išskiria anglies dioksidą, todėl tešla kyla. Leidžiamas tik keliose maisto kategorijose — pavyzdžiui, tam tikruose pieno produktuose rūgštingumui reguliuoti. Vienas seniausių ir geriausiai ištirtų priedų — saugumo klausimai nekyla.');
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (364381, '315530', '1.5', 'dehydrated milk as defined by directive 2001/114/ec', 'džiovintas pienas, kaip apibrėžta direktyvoje 2001/114/EB', 'FAD_RT_QS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (364381, '315558', '1.7.2', 'ripened cheese', 'subrandintas sūris', 'FAD_RT_QS', NULL, NULL, 'only sour milk cheese', 'tik rūgštaus pieno sūriai', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (364381, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additives (id, e_number, e_number_display, e_number_sort, display_name_en, display_name_lt, identifying_name_en, identifying_name_lt, synonyms_en, synonyms_lt, ins_number, is_group, member_of_group, policy_item_code, source_url, opinion_en, opinion_lt) VALUES (364441, 'E501(ii)', 'E 501(ii)', 501, 'Potassium hydrogen carbonate', 'Kalio hidrokarbonatas', 'Potassium hydrogen carbonate', 'Kalio hidrokarbonatas', NULL, NULL, NULL, FALSE, NULL, 'POL-FAD-IMPORT-3362', 'https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search', 'A mineral salt that acts as a leavening agent and acidity regulator. It releases carbon dioxide when heated, helping baked goods rise, and can neutralise excess acidity in food. Approved for very limited use — mainly in dehydrated milk products. Naturally occurring compound, considered safe at authorised levels with no significant health concerns.', 'Tai mineralinė druska, naudojama kaip rūgštingumo reguliatorius ir kildiklis. Kaitinama išskiria anglies dioksidą — tai padeda kepiniams kilti ir neutralizuoja perteklinį rūgštingumą. Leidžiama naudoti labai siauroje maisto kategorijoje — daugiausia dehidratuotuose pieno produktuose. Natūraliai pasitaikantis junginys, leidžiamomis dozėmis laikomas saugiu.');
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (364441, '315530', '1.5', 'dehydrated milk as defined by directive 2001/114/ec', 'džiovintas pienas, kaip apibrėžta direktyvoje 2001/114/EB', 'FAD_RT_QS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (364441, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
